"use client";

import { Button } from "@/components/ui/button";

interface WelcomeScreenProps {
    onQuickAction: (action: string, value?: string) => void;
    children: React.ReactNode;
}

export function WelcomeScreen({ onQuickAction, children }: WelcomeScreenProps) {
    const quickActions = [
        { emoji: '🧮', label: '公式计算', value: '公式计算' },
        { emoji: '📖', label: '学习课程', value: 'course' },
        { emoji: '🔍', label: '查找资料', value: '查找资料' },
    ];

    return (
        <div className="flex-1 flex flex-col items-center justify-center px-4 pt-16">
            <div className="w-full max-w-3xl flex flex-col items-center gap-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
                {children}

                <div className="flex flex-wrap justify-center gap-6 mt-2">
                    {quickActions.map((action) => (
                        <Button
                            key={action.label}
                            variant="outline"
                            className="rounded-full text-xs h-8 text-muted-foreground bg-background/50 backdrop-blur-sm"
                            onClick={() => onQuickAction(action.value, action.label)}
                        >
                            {action.emoji} {action.label}
                        </Button>
                    ))}
                </div>
            </div>
        </div>
    );
}