// app/home-page.tsx
"use client";

import { useState } from "react";
import { NavBar } from "@/components/layout/home-navbar";
import { ThemeToggle } from "@/components/ui/theme-toggle";
import { NotificationBanner } from "@/components/ui/notification-banner";
import { ChatInput } from "@/components/chat/chat-input";
import { MessageList } from "@/components/chat/message-list";
import { WelcomeScreen } from "@/components/chat/welcome-screen";
import { CourseList } from "@/components/course/course-list";

type View = 'chat' | 'course';

export default function HomePage() {
    const [messages, setMessages] = useState<{ role: 'user' | 'assistant'; content: string }[]>([]);
    const [view, setView] = useState<View>('chat');

    const handleSend = (content: string) => {
        setMessages([...messages, { role: 'user', content }]);
        setView('chat');
        // TODO: 调用 FastAPI 后端
    };

    const handleQuickAction = (action: string, label?: string) => {
        if (action === 'course') {
            setView('course');
        } else if (label) {
            handleSend(label);
        }
    };

    const renderContent = () => {
        if (view === 'course') {
            return <CourseList />;
        }

        if (messages.length === 0) {
            return (
                <WelcomeScreen onQuickAction={handleQuickAction}>
                    <ChatInput onSend={handleSend} />
                </WelcomeScreen>
            );
        }

        return (
            <>
                <MessageList messages={messages} />
                <div className="absolute bottom-8 left-0 right-0 w-full max-w-3xl mx-auto px-4 z-40 animate-in slide-in-from-bottom-6 duration-500">
                    <ChatInput onSend={handleSend} />
                </div>
            </>
        );
    };

    return (
        <div className="flex flex-col h-full w-full bg-background transition-colors duration-500 overflow-hidden relative">
            <div className="absolute top-0 left-0 right-0 flex flex-col items-center pt-6 z-40 pointer-events-none">
                <div className="pointer-events-auto flex flex-col items-center">
                    <NavBar />
                    <NotificationBanner />
                </div>
            </div>

            <header className="absolute top-0 w-full p-4 flex justify-end items-center z-50 pointer-events-none">
                <ThemeToggle />
            </header>

            {renderContent()}
        </div>
    );
}